    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof regenerateWidget>>, TError,{key: string;id: string}, TContext>, }
): UseMutationOptions<Awaited<ReturnType<typeof regenerateWidget>>, TError,{key: string;id: string}, TContext> => {

const mutationKey = ['regenerateWidget'];
const {mutation: mutationOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }};

      


      const mutationFn: MutationFunction<Awaited<ReturnType<typeof regenerateWidget>>, {key: string;id: string}> = (props) => {
          const {key,id} = props ?? {};

          return  regenerateWidget(key,id,)
        }

        


  return  { mutationFn, ...mutationOptions }}

    export type RegenerateWidgetMutationResult = NonNullable<Awaited<ReturnType<typeof regenerateWidget>>>
    
    export type RegenerateWidgetMutationError = ErrorType<Error>

    /**
 * @summary Reseed a chart widget (new random data)
 */
export const useRegenerateWidget = <TError = ErrorType<Error>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof regenerateWidget>>, TError,{key: string;id: string}, TContext>, }
 , queryClient?: QueryClient): UseMutationResult<
        Awaited<ReturnType<typeof regenerateWidget>>,
        TError,
        {key: string;id: string},
        TContext
      > => {

      const mutationOptions = getRegenerateWidgetMutationOptions(options);

      return useMutation(mutationOptions, queryClient);
    }
